package cc.arccore.di.generated.injector

import cc.arccore.api.di.exception.InjectorLoadException
import cc.arccore.api.di.generated.GeneratedInjector
import cc.arccore.di.generated.injector.validation.InjectorValidator

/**
 * Loads generated injectors from `META-INF/arc/generated/injectors.list` at
 * module startup.
 *
 * The list file is generated by KSP (GraphGenerator) — one factory class name
 * per line. Using a flat text file avoids a JSON parsing dependency in arc-di:
 * the format is entirely controlled by the generator, so it can be kept trivial.
 *
 * WHY load from META-INF and not from a hardcoded class name:
 * - Multiple modules can be loaded in the same JVM with different ClassLoaders.
 * - The path is module-ClassLoader-relative, so each module sees only its own
 *   factories. There is no global registry that would create ClassLoader leaks.
 * - Any missing/stale class is skipped with a warning rather than crashing the
 *   module load — the reflection fallback in [DefaultDIContainer] will handle it.
 */
object InjectorLoader {

    private const val INJECTORS_LIST_PATH = "META-INF/arc/generated/injectors.list"

    private val validator = InjectorValidator()

    fun load(classLoader: ClassLoader): List<GeneratedInjector<*>> {
        val stream = classLoader.getResourceAsStream(INJECTORS_LIST_PATH) ?: return emptyList()
        return stream.bufferedReader().use { reader ->
            reader.lineSequence()
                .map { it.trim() }
                .filter { it.isNotEmpty() && !it.startsWith('#') }
                .mapNotNull { line -> loadOne(line, classLoader) }
                .toList()
        }
    }

    private fun loadOne(factoryClassName: String, classLoader: ClassLoader): GeneratedInjector<*>? {
        val injector = try {
            val clazz = classLoader.loadClass(factoryClassName)
            clazz.getDeclaredConstructor().newInstance() as GeneratedInjector<*>
        } catch (_: ClassNotFoundException) {
            // stale entry from an incremental build — skip gracefully
            return null
        } catch (e: ClassCastException) {
            throw InjectorLoadException(
                "'$factoryClassName' does not implement GeneratedInjector — " +
                    "stale or mismatched generated artifact", e
            )
        } catch (e: Exception) {
            throw InjectorLoadException(
                "Failed to instantiate '$factoryClassName': ${e.message}", e
            )
        }

        return when (val result = validator.validate(injector, classLoader)) {
            InjectorValidator.ValidationResult.Valid -> injector
            is InjectorValidator.ValidationResult.Invalid -> {
                // Log warning but don't crash — reflection fallback handles this type
                System.err.println("[ARCCore DI] Skipping invalid injector '$factoryClassName': ${result.reason}")
                null
            }
        }
    }
}
